from pymongo import MongoClient

# Connect to MongoDB
client = MongoClient("mongodb://localhost:27017")

# Select the database and collection
db = client["mydatabase"]
collection = db["mycollection"]

# Accept user-provided filter expression
filter_expression = input("Enter a JavaScript expression for filtering documents: ")

# Execute the query using $where operator
result = collection.find({"$where": filter_expression})

# Print the results
for document in result:
    print(document)